  1→/* Maimai Assistant - Custom Styles */
  2→
  3→/* Connection badge */
  4→.badge {
  5→    display: inline-block;
  6→    padding: 0.2em 0.6em;
  7→    font-size: 0.75em;
  8→    font-weight: 600;
  9→    border-radius: 1em;
 10→    background: var(--pico-secondary-background);
 11→    color: var(--pico-secondary);
 12→}
 13→
 14→.badge[data-status="ok"],
 15→.badge[data-status="completed"],
 16→.badge[data-status="sent"] {
 17→    background: #d4edda;
 18→    color: #155724;
 19→}
 20→
 21→.badge[data-status="warn"],
 22→.badge[data-status="running"],
 23→.badge[data-status="in_progress"],
 24→.badge[data-status="queued"] {
 25→    background: #fff3cd;
 26→    color: #856404;
 27→}
 28→
 29→.badge[data-status="error"],
 30→.badge[data-status="failed"],
 31→.badge[data-status="cancelled"] {
 32→    background: #f8d7da;
 33→    color: #721c24;
 34→}
 35→
 36→.badge[data-status="awaiting_confirmation"] {
 37→    background: #cce5ff;
 38→    color: #004085;
 39→}
 40→
 41→/* Status bar */
 42→#status-bar {
 43→    display: flex;
 44→    gap: 1.5rem;
 45→    align-items: center;
 46→    padding: 0.4rem 0.8rem;
 47→    background: var(--pico-card-background-color);
 48→    border: 1px solid var(--pico-muted-border-color);
 49→    border-radius: var(--pico-border-radius);
 50→    font-size: 0.85em;
 51→    margin-bottom: 1.5rem;
 52→}
 53→
 54→#status-bar .status-item {
 55→    display: flex;
 56→    align-items: center;
 57→    gap: 0.3rem;
 58→}
 59→
 60→#status-bar .dot {
 61→    width: 8px;
 62→    height: 8px;
 63→    border-radius: 50%;
 64→    background: var(--pico-muted-color);
 65→}
 66→
 67→#status-bar .dot[data-ok="true"] { background: #28a745; }
 68→#status-bar .dot[data-ok="false"] { background: #dc3545; }
 69→
 70→/* Status hint banner */
 71→#status-hint {
 72→    font-size: 0.85em;
 73→    line-height: 1.5;
 74→    padding: 0.6rem 0.8rem;
 75→    border-radius: var(--pico-border-radius);
 76→    margin-bottom: 1rem;
 77→}
 78→#status-hint code {
 79→    font-size: 0.85em;
 80→    word-break: break-all;
 81→}
 82→.status-hint-err {
 83→    background: #f8d7da;
 84→    color: #721c24;
 85→    border: 1px solid #f5c6cb;
 86→}
 87→.status-hint-warn {
 88→    background: #fff3cd;
 89→    color: #856404;
 90→    border: 1px solid #ffeeba;
 91→}
 92→
 93→/* Tabs */
 94→.tabs {
 95→    display: flex;
 96→    gap: 0;
 97→    border-bottom: 2px solid var(--pico-muted-border-color);
 98→    margin-bottom: 1.5rem;
 99→}
100→
101→.tabs .tab {
102→    padding: 0.6rem 1.2rem;
103→    cursor: pointer;
104→    font-weight: 500;
105→    border-bottom: 2px solid transparent;
106→    margin-bottom: -2px;
107→    color: var(--pico-muted-color);
108→    background: none;
109→    border-top: none;
110→    border-left: none;
111→    border-right: none;
112→    font-size: 1em;
113→}
114→
115→.tabs .tab:hover {
116→    color: var(--pico-color);
117→}
118→
119→.tabs .tab.active {
120→    color: var(--pico-primary);
121→    border-bottom-color: var(--pico-primary);
122→}
123→
124→.tab-content { display: none; }
125→.tab-content.active { display: block; }
126→
127→/* Pipeline log */
128→#pipeline-log {
129→    max-height: 240px;
130→    overflow-y: auto;
131→    font-size: 0.82em;
132→    font-family: var(--pico-font-family-monospace, monospace);
133→    line-height: 1.6;
134→    margin-top: 0.5rem;
135→    padding: 0.5rem 0;
136→    border-top: 1px solid var(--pico-muted-border-color);
137→}
138→
139→#pipeline-log .log-line {
140→    padding: 0.15rem 0;
141→}
142→
143→#pipeline-log .log-time {
144→    color: var(--pico-muted-color);
145→    margin-right: 0.5em;
146→}
147→
148→#pipeline-log .log-ok { color: #155724; }
149→#pipeline-log .log-err { color: #721c24; }
150→#pipeline-log .log-info { color: var(--pico-color); }
151→#pipeline-log .log-warn { color: #856404; }
152→
153→/* Messaging options (hidden when search-only) */
154→#messaging-options.hidden { display: none; }
155→
156→/* Nav spacing */
157→nav {
158→    padding-top: 0.5rem;
159→    padding-bottom: 0.5rem;
160→}
161→
162→nav ul li a {
163→    font-size: 0.9em;
164→}
165→
166→/* Article cards */
167→article {
168→    margin-bottom: 1rem;
169→}
170→
171→article header {
172→    font-weight: 600;
173→}
174→
175→/* Table tweaks */
176→table {
177→    font-size: 0.9em;
178→}
179→
180→table td, table th {
181→    padding: 0.5em 0.75em;
182→}
183→
184→/* Candidate checkboxes in pipeline confirm */
185→#candidate-list {
186→    max-height: 400px;
187→    overflow-y: auto;
188→    border: 1px solid var(--pico-muted-border-color);
189→    border-radius: var(--pico-border-radius);
190→    padding: 0.5rem;
191→}
192→
193→#candidate-list label {
194→    display: flex;
195→    align-items: center;
196→    gap: 0.5rem;
197→    padding: 0.4rem 0;
198→    border-bottom: 1px solid var(--pico-muted-border-color);
199→    margin-bottom: 0;
200→}
201→
202→#candidate-list label:last-child {
203→    border-bottom: none;
204→}
205→
206→#candidate-list .candidate-info {
207→    flex: 1;
208→    display: flex;
209→    gap: 1rem;
210→}
211→
212→#candidate-list .candidate-name {
213→    font-weight: 600;
214→    min-width: 80px;
215→}
216→
217→#candidate-list .candidate-title {
218→    color: var(--pico-muted-color);
219→    flex: 1;
220→}
221→
222→#candidate-list .candidate-company {
223→    color: var(--pico-primary);
224→}
225→
226→/* Pagination controls */
227→.pagination-controls {
228→    display: flex;
229→    align-items: center;
230→    justify-content: center;
231→    gap: 1rem;
232→    margin-top: 1rem;
233→}
234→
235→.pagination-controls button {
236→    width: auto;
237→    margin: 0;
238→}
239→
240→/* Progress bar animations */
241→progress {
242→    transition: value 0.3s ease;
243→}
244→
245→/* Results summary */
246→#results-summary .stat-grid {
247→    display: grid;
248→    grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
249→    gap: 0.5rem;
250→    margin-top: 0.5rem;
251→}
252→
253→#results-summary .stat {
254→    text-align: center;
255→    padding: 0.5rem;
256→    border-radius: var(--pico-border-radius);
257→    background: var(--pico-card-background-color);
258→}
259→
260→#results-summary .stat .value {
261→    font-size: 1.5em;
262→    font-weight: 700;
263→}
264→
265→#results-summary .stat .label {
266→    font-size: 0.8em;
267→    color: var(--pico-muted-color);
268→}
269→
270→/* Footer */
271→footer {
272→    margin-top: 2rem;
273→    padding-top: 1rem;
274→    border-top: 1px solid var(--pico-muted-border-color);
275→    text-align: center;
276→    color: var(--pico-muted-color);
277→}
278→

  1→{% extends "base.html" %}
  2→
  3→{% block title %}Pipeline - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<!-- Status bar -->
  7→<div id="status-bar">
  8→    <div class="status-item">
  9→        <span class="dot" id="browser-dot"></span>
 10→        <span>Browser: <strong id="browser-status">--</strong></span>
 11→    </div>
 12→    <div class="status-item">
 13→        <span class="dot" id="login-dot"></span>
 14→        <span>Login: <strong id="login-status">--</strong></span>
 15→    </div>
 16→    <div class="status-item">
 17→        Queue: <strong id="queue-size">0</strong>
 18→    </div>
 19→</div>
 20→<div id="status-hint" hidden></div>
 21→
 22→<!-- Unified form -->
 23→<form id="pipeline-form">
 24→    <div class="grid">
 25→        <label>
 26→            Keywords (one per line)
 27→            <textarea name="keywords" rows="3" placeholder="e.g. 前端工程师" required></textarea>
 28→        </label>
 29→        <label>
 30→            Company filter (one per line, optional)
 31→            <textarea name="company" rows="3" placeholder="e.g. 字节跳动"></textarea>
 32→        </label>
 33→    </div>
 34→    <div class="grid">
 35→        <label>
 36→            Location (optional)
 37→            <input type="text" name="location" placeholder="e.g. 北京">
 38→        </label>
 39→        <label>
 40→            Template
 41→            <select name="template" id="template-select">
 42→                <option value="">-- Search only --</option>
 43→            </select>
 44→        </label>
 45→        <label>
 46→            Pages
 47→            <input type="number" name="pages" value="1" min="1" max="50">
 48→        </label>
 49→    </div>
 50→    <div id="template-vars"></div>
 51→    <fieldset id="messaging-options" class="hidden">
 52→        <label>
 53→            <input type="checkbox" name="auto_send">
 54→            Auto-send (skip candidate confirmation)
 55→        </label>
 56→    </fieldset>
 57→    <button type="submit" id="submit-btn">Search</button>
 58→</form>
 59→
 60→<!-- Progress section -->
 61→<div id="pipeline-progress" hidden>
 62→    <article>
 63→        <header>
 64→            <span id="pipeline-status-text">Queued...</span>
 65→            <span id="pipeline-task-id" class="badge" style="float:right"></span>
 66→        </header>
 67→        <progress id="pipeline-progress-bar" value="0" max="100"></progress>
 68→        <p id="pipeline-detail"></p>
 69→        <div id="pipeline-log"></div>
 70→    </article>
 71→</div>
 72→
 73→<!-- Confirmation section (manual mode) -->
 74→<div id="pipeline-confirm" hidden>
 75→    <article>
 76→        <header>Select Candidates to Message</header>
 77→        <p>
 78→            <label>
 79→                <input type="checkbox" id="select-all" onchange="toggleSelectAll(this.checked)">
 80→                Select All (<span id="confirm-count">0</span> candidates)
 81→            </label>
 82→        </p>
 83→        <div id="candidate-list"></div>
 84→        <footer>
 85→            <button onclick="confirmCandidates()" class="primary">Confirm & Send</button>
 86→            <button onclick="confirmCandidates(true)" class="secondary outline">Cancel</button>
 87→        </footer>
 88→    </article>
 89→</div>
 90→
 91→<!-- Search results (search-only mode) -->
 92→<div id="search-results" hidden>
 93→    <h3>Results (<span id="result-count">0</span> candidates)</h3>
 94→    <table>
 95→        <thead>
 96→            <tr>
 97→                <th>#</th>
 98→                <th>Name</th>
 99→                <th>Title</th>
100→                <th>Company</th>
101→                <th>Location</th>
102→            </tr>
103→        </thead>
104→        <tbody id="results-body"></tbody>
105→    </table>
106→    <button id="export-btn" class="outline" onclick="exportResults()">Export to Excel</button>
107→</div>
108→
109→<!-- Pipeline results -->
110→<div id="pipeline-results" hidden>
111→    <article>
112→        <header>Pipeline Complete</header>
113→        <div id="results-summary"></div>
114→    </article>
115→</div>
116→{% endblock %}
117→
118→{% block scripts %}
119→<script src="/static/js/pipeline.js"></script>
120→<script>
121→// --- Status bar auto-refresh ---
122→async function refreshStatus() {
123→    try {
124→        const [authRes, statusRes] = await Promise.all([
125→            fetch('/api/auth/status'),
126→            fetch('/api/status'),
127→        ]);
128→        const auth = await authRes.json();
129→        const status = await statusRes.json();
130→
131→        const bDot = document.getElementById('browser-dot');
132→        const lDot = document.getElementById('login-dot');
133→        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
134→        bDot.dataset.ok = auth.browser_connected;
135→        document.getElementById('login-status').textContent = auth.logged_in ? 'OK' : 'No';
136→        lDot.dataset.ok = auth.logged_in;
137→        document.getElementById('queue-size').textContent = status.queue.queue_size;
138→
139→        // Status hint
140→        const hint = document.getElementById('status-hint');
141→        if (!auth.browser_connected) {
142→            hint.hidden = false;
143→            hint.className = 'status-hint-err';
144→            hint.innerHTML = '<strong>Browser 未连接</strong> — 请先启动 Chrome 调试模式：<br>' +
145→                '<code>/Applications/Google\\ Chrome.app/Contents/MacOS/Google\\ Chrome --remote-debugging-port=9222 --user-data-dir=/tmp/chrome-debug-profile</code>';
146→        } else if (!auth.logged_in) {
147→            hint.hidden = false;
148→            hint.className = 'status-hint-warn';
149→            hint.innerHTML = '<strong>未登录脉脉</strong> — 请在已启动的 Chrome 中打开 <a href="https://maimai.cn" target="_blank">maimai.cn</a> 并手动登录，登录后此状态会自动刷新。';
150→        } else {
151→            hint.hidden = true;
152→        }
153→
154→        // Update connection badge in nav
155→        const badge = document.getElementById('connection-badge');
156→        if (auth.browser_connected && auth.logged_in) {
157→            badge.textContent = 'Online';
158→            badge.dataset.status = 'ok';
159→        } else if (auth.browser_connected) {
160→            badge.textContent = 'Not Logged In';
161→            badge.dataset.status = 'warn';
162→        } else {
163→            badge.textContent = 'Offline';
164→            badge.dataset.status = 'error';
165→        }
166→    } catch (e) {
167→        console.error('Status refresh failed:', e);
168→    }
169→}
170→refreshStatus();
171→setInterval(refreshStatus, 10000);
172→
173→// --- Template loading & mode switching ---
174→(async () => {
175→    try {
176→        const res = await fetch('/api/templates');
177→        const templates = await res.json();
178→        const select = document.getElementById('template-select');
179→        // Append template options after the "Search only" default
180→        select.innerHTML = '<option value="">-- Search only --</option>' +
181→            templates.map(t =>
182→                `<option value="${t.name}">${t.name} — ${t.description || 'No description'}</option>`
183→            ).join('');
184→
185→        function onTemplateChange() {
186→            const tpl = templates.find(t => t.name === select.value);
187→            const msgOpts = document.getElementById('messaging-options');
188→            const submitBtn = document.getElementById('submit-btn');
189→            const varsDiv = document.getElementById('template-vars');
190→
191→            if (select.value) {
192→                // Pipeline mode
193→                msgOpts.classList.remove('hidden');
194→                submitBtn.textContent = 'Start Pipeline';
195→                if (tpl && tpl.variables.length) {
196→                    const autoVars = ['name', 'company', 'position'];
197→                    const manualVars = tpl.variables.filter(v => !autoVars.includes(v));
198→                    if (manualVars.length) {
199→                        varsDiv.innerHTML = '<fieldset><legend>Template Variables</legend>' +
200→                            manualVars.map(v =>
201→                                `<label>${v}<input type="text" name="var_${v}" placeholder="${v}"></label>`
202→                            ).join('') + '</fieldset>';
203→                    } else {
204→                        varsDiv.innerHTML = '<small>Variables (name, company, position) will be auto-filled per candidate.</small>';
205→                    }
206→                } else {
207→                    varsDiv.innerHTML = '';
208→                }
209→            } else {
210→                // Search-only mode
211→                msgOpts.classList.add('hidden');
212→                submitBtn.textContent = 'Search';
213→                varsDiv.innerHTML = '';
214→            }
215→        }
216→
217→        select.addEventListener('change', onTemplateChange);
218→        onTemplateChange(); // init
219→    } catch (e) {
220→        console.error('Failed to load templates:', e);
221→    }
222→})();
223→</script>
224→{% endblock %}
