108→        appendLog(`Starting pipeline: ${keywords.join(', ')} | template=${template} | auto_send=${auto_send}`);
109→
110→        try {
111→            const res = await fetch('/api/pipeline', {
112→                method: 'POST',
113→                headers: {'Content-Type': 'application/json'},
114→                body: JSON.stringify({keywords, company, template, pages, variables, auto_send}),
