157→function handlePipelineEvent(msg) {
158→    const statusEl = document.getElementById('pipeline-status-text');
159→    const detailEl = document.getElementById('pipeline-detail');
160→    const progressBar = document.getElementById('pipeline-progress-bar');
161→
162→    switch (msg.event) {
163→        case 'search_progress':
164→            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
165→            appendLog(`Searching keyword ${msg.keyword_index}/${msg.total_keywords}: "${msg.keyword}"`);
166→            break;
167→
168→        case 'search_keyword_done':
169→            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
170→            appendLog(`"${msg.keyword}" — found ${msg.found} (total: ${msg.total_so_far})`, 'ok');
171→            break;
172→
173→        case 'search_complete':
174→            statusEl.textContent = 'Search complete';
175→            detailEl.textContent = `${msg.candidates.length} candidates found`;
176→            appendLog(`Search phase done — ${msg.candidates.length} candidates`, 'ok');
177→            break;
178→
179→        case 'awaiting_confirmation':
180→            statusEl.textContent = 'Awaiting your confirmation';
181→            appendLog(`Waiting for confirmation — ${msg.candidates.length} candidates to review`, 'warn');
182→            document.getElementById('pipeline-progress').hidden = true;
183→            showConfirmation(msg.candidates);
184→            break;
185→
186→        case 'sending_started':
187→            statusEl.textContent = 'Sending messages...';
188→            progressBar.max = msg.total;
189→            progressBar.value = 0;
190→            document.getElementById('pipeline-progress').hidden = false;
191→            document.getElementById('pipeline-confirm').hidden = true;
192→            appendLog(`Sending messages to ${msg.total} candidates...`);
193→            break;
194→
195→        case 'send_progress':
196→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
197→            progressBar.value = msg.sent + msg.failed;
198→            progressBar.max = msg.total;
199→            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
200→            if (msg.status === 'sent') {
201→                appendLog(`Sent to ${msg.current}`, 'ok');
202→            } else if (msg.status === 'failed') {
203→                appendLog(`Failed: ${msg.current} — ${msg.error || 'unknown'}`, 'err');
204→            } else if (msg.status === 'skipped') {
205→                appendLog(`Skipped: ${msg.current}`, 'warn');
206→            } else {
207→                appendLog(`${msg.current} (${msg.sent}/${msg.total})`);
208→            }
209→            break;
210→
211→        case 'completed':
212→            appendLog('Pipeline completed', 'ok');
213→            showPipelineResults(msg.result);
214→            break;
215→
216→        default:
217→            appendLog(`${msg.event}: ${JSON.stringify(msg)}`);
218→    }
219→}
